import argparse
import json
import os
import signal
import sys
import time
from datetime import datetime

import pika

RABBITMQ_HOST = "localhost"
RABBITMQ_PORT = 5672
QUEUE_NAME = "task_queue"


def get_connection():
    credentials = None
    username = os.getenv("RABBITMQ_USERNAME")
    password = os.getenv("RABBITMQ_PASSWORD")
    if username and password:
        credentials = pika.PlainCredentials(username, password)

    params = pika.ConnectionParameters(
        host=RABBITMQ_HOST,
        port=RABBITMQ_PORT,
        credentials=credentials,
        heartbeat=60,
        blocked_connection_timeout=30,
    )
    return pika.BlockingConnection(params)


def setup_queue(channel):
    channel.queue_declare(queue=QUEUE_NAME, durable=True)


def publish_task(task_type, payload):
    connection = get_connection()
    try:
        channel = connection.channel()
        setup_queue(channel)
        message = {
            "task_type": task_type,
            "payload": payload,
            "created_at": datetime.utcnow().isoformat() + "Z",
        }
        channel.basic_publish(
            exchange="",
            routing_key=QUEUE_NAME,
            body=json.dumps(message).encode("utf-8"),
            properties=pika.BasicProperties(
                delivery_mode=2,
                content_type="application/json",
            ),
        )
        print(f"Published task: {message}")
    finally:
        connection.close()


def process_task(message):
    task_type = message.get("task_type", "unknown")
    payload = message.get("payload", {})
    print(f"Processing task_type={task_type} payload={payload}")
    time.sleep(1)
    print(f"Completed task_type={task_type}")


def consume_tasks():
    connection = get_connection()
    channel = connection.channel()
    setup_queue(channel)
    channel.basic_qos(prefetch_count=1)

    stopping = {"value": False}

    def handle_signal(signum, frame):
        stopping["value"] = True
        try:
            channel.stop_consuming()
        except Exception:
            pass

    signal.signal(signal.SIGINT, handle_signal)
    signal.signal(signal.SIGTERM, handle_signal)

    def callback(ch, method, properties, body):
        try:
            message = json.loads(body.decode("utf-8"))
            process_task(message)
            ch.basic_ack(delivery_tag=method.delivery_tag)
        except Exception as exc:
            print(f"Failed to process message: {exc}", file=sys.stderr)
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)

    channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)

    print(f"Waiting for messages on queue '{QUEUE_NAME}'. Press Ctrl+C to exit.")
    try:
        channel.start_consuming()
    finally:
        if not connection.is_closed:
            connection.close()


def main():
    parser = argparse.ArgumentParser(description="RabbitMQ task publisher/consumer")
    subparsers = parser.add_subparsers(dest="command", required=True)

    publish_parser = subparsers.add_parser("publish", help="Publish a task")
    publish_parser.add_argument("--task-type", required=True, help="Task type")
    publish_parser.add_argument(
        "--payload",
        default="{}",
        help='Task payload as JSON string, e.g. \'{"id": 1}\'',
    )

    subparsers.add_parser("consume", help="Consume tasks")

    args = parser.parse_args()

    if args.command == "publish":
        try:
            payload = json.loads(args.payload)
        except json.JSONDecodeError as exc:
            print(f"Invalid JSON payload: {exc}", file=sys.stderr)
            sys.exit(1)
